import{_ as a,o as p,c as r,ak as t}from"./chunks/framework.aEAtsvX-.js";const u=JSON.parse('{"title":"区块漏斗","description":"","frontmatter":{},"headers":[],"relativePath":"plugins/upgradeable_hoppers.md","filePath":"plugins/upgradeable_hoppers.md","lastUpdated":1775875213000}'),o={name:"plugins/upgradeable_hoppers.md"};function s(n,e,d,c,l,_){return p(),r("div",null,[...e[0]||(e[0]=[t('<h1 id="区块漏斗" tabindex="-1">区块漏斗 <a class="header-anchor" href="#区块漏斗" aria-label="Permalink to “区块漏斗”">​</a></h1><p><strong>Upgradeable Hoppers</strong> 是一个 Minecraft 服务器插件（Spigot/Bukkit），其核心功能是<strong>用单个高性能漏斗替代复杂的漏斗链</strong>，从而大幅减少服务器因实体漏斗产生的 Tick 延迟（TPS Lag）。</p><p><strong>区块级吸取（Chunk Suction）</strong>：漏斗可以设置为“区块吸取”模式，自动拾取整个区块（或指定半径）内掉落在地面上的物品，无需使用水流或漏斗矿车收集。</p><hr><p>由于是测试,价格会进行调整,不是最终结果。 只能在自己的领土或被信任的领土中使用。领土中被信任的其他人或领土拥有者可以编辑区块漏斗的设置</p><p>主要命令:<code>/uhoppers help</code> 查看管理已放置的升级漏斗命令:<code>/uhoppers list</code> 购买漏斗命令:<code>/uhoppers get</code> 默认normal或chunk 左键升级漏斗打开交互菜单,右键打开漏斗,可潜行时用工具破坏回收已放置的升级漏斗.</p>',6)])])}const g=a(o,[["render",s]]);export{u as __pageData,g as default};
